mapper.select:
select a.id, a.title, a.slug, a.summary, a.cover_image, a.category_id, ac.name as category_name, a.view_count, a.like_count, a.comment_count, a.word_count, a.reading_time, a.is_published, a.is_top, a.publish_time, a.create_time, a.update_time from articles a left join article_categories ac on a.category_id = ac.id
and a.title like concat('%', #{title}, '%')
and a.category_id = #{categoryId}
and a.is_published = #{isPublished}
order by a.is_top desc, a.create_time desc

mapper.update:
update articles
title = #{title}, slug = #{slug}, summary = #{summary}, cover_image = #{coverImage}, content_markdown = #{contentMarkdown}, content_html = #{contentHtml}, category_id = #{categoryId}, word_count = #{wordCount}, reading_time = #{readingTime}, is_published = #{isPublished}, is_top = #{isTop}, publish_time = #{publishTime}, update_time = #{updateTime}
where id = #{id}
